// RISK_OF_BIAS_v2 (v0.2.9) - multi-outils : RoB 2, Jadad, PEDro, ROBINS-I, Newcastle-Ottawa,
// Downs & Black, AXIS, QUADAS-2, AMSTAR-2, ROBIS. Auto-detection du design + override manuel.
// 1 item = 1 question -> reponse + justification ; score global calcule en code si defini.
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const articles = items.map(i => i.json);
console.log('[RoB v2] ' + articles.length + ' articles');

// ===== CATALOGUE D'OUTILS =====
// kind: 'judgment' (jugement par domaine + overall) | 'score' (somme) | 'count' (info) | 'matrix' (QUADAS-2)
const TOOLS = {
  rob2: { name:'RoB 2', family:'rct', kind:'judgment', overall:true,
    answers:['low','some_concerns','high'],
    items:[['randomization','Bias arising from the randomization process'],['deviations','Bias due to deviations from intended interventions'],['missing_data','Bias due to missing outcome data'],['outcome_measurement','Bias in measurement of the outcome'],['selection_reporting','Bias in selection of the reported result']] },
  jadad: { name:'Jadad', family:'rct', kind:'score', scoreMax:5,
    answers:['yes','no'],
    items:[['randomized','Was the study described as randomized?'],['rand_method','Was the method of randomization appropriate?'],['double_blind','Was the study described as double-blind?'],['blind_method','Was the method of blinding appropriate?'],['withdrawals','Were withdrawals and dropouts described?']] },
  pedro: { name:'PEDro', family:'rct', kind:'score', scoreMax:10,
    answers:['yes','no'],
    items:[['eligibility','Eligibility criteria were specified (not scored)',{noScore:true}],['random_alloc','Subjects were randomly allocated to groups'],['concealed_alloc','Allocation was concealed'],['baseline_similar','Groups were similar at baseline'],['blind_subjects','Blinding of all subjects'],['blind_therapists','Blinding of all therapists'],['blind_assessors','Blinding of all assessors (key outcome)'],['followup','Outcomes obtained from >85% of subjects'],['itt','Intention-to-treat analysis'],['between_group','Between-group statistical comparison reported'],['point_variability','Point measures and variability reported']] },
  robinsi: { name:'ROBINS-I', family:'nonrandomized', kind:'judgment', overall:true,
    answers:['low','moderate','serious','critical','no_information'],
    items:[['confounding','Bias due to confounding'],['selection','Bias in selection of participants into the study'],['classification','Bias in classification of interventions'],['deviations','Bias due to deviations from intended interventions'],['missing_data','Bias due to missing data'],['outcome_measurement','Bias in measurement of outcomes'],['selection_reporting','Bias in selection of the reported result']] },
  nos: { name:'Newcastle-Ottawa', family:'nonrandomized', kind:'score', scoreMax:9, scoreLabel:'stars',
    answers:['yes','no'],
    items:[['sel_representativeness','Selection: representativeness of the exposed/case group'],['sel_selection','Selection: selection of the non-exposed/controls'],['sel_exposure','Selection: ascertainment of exposure'],['sel_outcome_absent','Selection: outcome not present at start'],['comp_main','Comparability: controls for the most important factor (1 star)'],['comp_additional','Comparability: controls for any additional factor (1 star)'],['out_assessment','Outcome/Exposure: assessment method'],['out_followup_length','Outcome: follow-up long enough for outcomes to occur'],['out_followup_adequacy','Outcome: adequacy of follow-up of cohorts']] },
  downs: { name:'Downs & Black', family:'nonrandomized', kind:'score', scoreMax:28,
    answers:['yes','partial','no'],
    items:[['r_hypothesis','Reporting: aim/hypothesis clearly described'],['r_outcomes','Reporting: main outcomes clearly described'],['r_patients','Reporting: patient characteristics described'],['r_interventions','Reporting: interventions clearly described'],['r_confounders','Reporting: principal confounders described',{vals:{yes:2,partial:1,no:0}}],['r_findings','Reporting: main findings clearly described'],['r_variability','Reporting: estimates of random variability given'],['r_adverse','Reporting: adverse events reported'],['r_lost','Reporting: characteristics of patients lost to follow-up'],['r_probability','Reporting: actual probability values reported'],['ev_source','External validity: subjects representative of source population'],['ev_recruited','External validity: subjects representative of those recruited'],['ev_settings','External validity: settings representative of usual care'],['iv_blind_subjects','Internal validity: subjects blinded to intervention'],['iv_blind_assessors','Internal validity: assessors blinded to outcome'],['iv_dataredging','Internal validity: no data dredging / analyses planned'],['iv_followup_adjust','Internal validity: analyses adjust for different follow-up'],['iv_stats','Internal validity: appropriate statistical tests'],['iv_compliance','Internal validity: reliable compliance with intervention'],['iv_outcome_measures','Internal validity: accurate/valid outcome measures'],['conf_same_pop','Confounding: cases and controls from same population'],['conf_same_period','Confounding: recruited over same time period'],['conf_randomized','Confounding: subjects randomized'],['conf_conceal','Confounding: randomized allocation concealed'],['conf_adjust','Confounding: adequate adjustment for confounding'],['conf_lost_account','Confounding: losses to follow-up accounted for'],['power','Power: study had sufficient power to detect an effect']] },
  axis: { name:'AXIS (cross-sectional)', family:'cross_sectional', kind:'count', countMax:20,
    answers:['yes','no','dont_know'],
    items:[['aims','Were the aims/objectives clear?'],['design_appropriate','Was the study design appropriate?'],['sample_justified','Was the sample size justified?'],['target_defined','Was the target/reference population clearly defined?'],['sample_frame','Was the sample frame from an appropriate base?'],['selection_process','Was the selection process likely to select representative subjects?'],['nonresponders','Were measures taken to address non-responders?'],['vars_measured','Were the variables measured appropriate to the aims?'],['instruments_valid','Were the measurement instruments valid and reliable?'],['stats_significance','Was it clear what was used to determine statistical significance?'],['methods_repeatable','Were the methods sufficiently described to be repeatable?'],['basic_data','Were the basic data adequately described?'],['response_concerns','Was the response rate raising concerns about non-response bias?'],['nonresponse_info','Was information about non-responders described?'],['results_internally_consistent','Were the results internally consistent?'],['results_for_analyses','Were results presented for all analyses described?'],['discussion_justified','Were the discussion/conclusions justified by the results?'],['limitations','Were the limitations discussed?'],['funding_conflicts','Were there concerns about funding/conflicts of interest?'],['ethics','Was ethical approval / consent attained?']] },
  quadas2: { name:'QUADAS-2', family:'diagnostic', kind:'matrix',
    answers:['low','high','unclear'],
    items:[['rob_patient_selection','Risk of bias: patient selection'],['rob_index_test','Risk of bias: index test'],['rob_reference_standard','Risk of bias: reference standard'],['rob_flow_timing','Risk of bias: flow and timing'],['app_patient_selection','Applicability: patient selection'],['app_index_test','Applicability: index test'],['app_reference_standard','Applicability: reference standard']] },
  amstar2: { name:'AMSTAR-2', family:'systematic_review', kind:'judgment', overall:true, overallKind:'confidence',
    answers:['yes','partial_yes','no'],
    critical:['protocol_priori','search_comprehensive','rob_technique','rob_interpretation','meta_methods','rob_discussion','pub_bias'],
    items:[['pico','Did the research questions include PICO components?'],['protocol_priori','Was there an a priori protocol / registration?',{critical:true}],['design_selection','Was study design selection explained?'],['search_comprehensive','Was a comprehensive literature search performed?',{critical:true}],['dup_selection','Was study selection performed in duplicate?'],['dup_extraction','Was data extraction performed in duplicate?'],['excluded_list','Was a list of excluded studies with justification provided?'],['included_detail','Were included studies described in adequate detail?'],['rob_technique','Was a satisfactory risk-of-bias technique used?',{critical:true}],['funding_sources','Were sources of funding of included studies reported?'],['meta_methods','Were appropriate methods used for meta-analysis?',{critical:true}],['rob_impact','Was the impact of risk of bias on results assessed?'],['rob_interpretation','Was risk of bias accounted for when interpreting results?',{critical:true}],['heterogeneity','Was heterogeneity satisfactorily investigated/discussed?'],['pub_bias','Was publication bias investigated and its impact discussed?',{critical:true}],['conflicts','Were conflicts of interest / funding declared?']] },
  robis: { name:'ROBIS', family:'systematic_review', kind:'judgment', overall:true,
    answers:['low','high','unclear'],
    items:[['eligibility','Phase 2 - Domain 1: study eligibility criteria'],['identification_selection','Phase 2 - Domain 2: identification and selection of studies'],['data_collection_appraisal','Phase 2 - Domain 3: data collection and study appraisal'],['synthesis_findings','Phase 2 - Domain 4: synthesis and findings']] }
};

const DEFAULT_BY_FAMILY = { rct:'rob2', nonrandomized:'robinsi', cross_sectional:'axis', diagnostic:'quadas2', systematic_review:'amstar2' };

function detectFamily(a) {
  const t = ((a.title||'') + ' ' + (a.abstract||'')).toLowerCase();
  if (/meta-analysis|systematic review|prisma|pooled analysis/.test(t)) return 'systematic_review';
  if (/diagnostic accuracy|sensitivity and specificity|index test|reference standard|roc curve/.test(t)) return 'diagnostic';
  if (/randomi[sz]ed controlled trial|\brct\b|randomly assigned|double-blind|placebo-controlled/.test(t)) return 'rct';
  if (/cross-sectional|prevalence survey|questionnaire survey/.test(t)) return 'cross_sectional';
  if (/cohort|case-control|case control|observational|registry|retrospective|prospective study|non-randomi/.test(t)) return 'nonrandomized';
  return 'unknown';
}

function recon(inv){ if(!inv) return ''; const w=[]; for(const k in inv){ const ps=inv[k]; for(let i=0;i<ps.length;i++){ w[ps[i]]=k; } } return w.join(' ').replace(/\s+/g,' ').trim().substring(0,2000); }
function extractJson(raw){ if(!raw) return null; let s=String(raw).replace(/```json/gi,'').replace(/```/g,''); const i=s.indexOf('{'),j=s.lastIndexOf('}'); if(i<0||j<=i) return null; const f=s.substring(i,j+1); try{return JSON.parse(f);}catch(e){} try{return JSON.parse(f.replace(/,\s*([}\]])/g,'$1'));}catch(e){} return null; }

function normVal(v){ return (v==null?'':String(v)).toLowerCase().replace(/\s+/g,'_').replace(/[^a-z_]/g,''); }

function computeScore(tool, parsedItems){
  // retourne {score, max} ou null
  if (tool.kind === 'score') {
    let s=0, max=0;
    for (const it of tool.items){ const k=it[0], opts=it[2]||{}; if(opts.noScore) continue; const vals=opts.vals||{yes:1,partial:0,no:0}; const itemMax=Math.max.apply(null,Object.keys(vals).map(function(x){return vals[x];})); max+=itemMax; const a=normVal((parsedItems[k]||{}).answer); s += (vals[a]!=null?vals[a]:0); }
    return { score:s, max:(tool.scoreMax||max) };
  }
  if (tool.kind === 'count') {
    let y=0; for (const it of tool.items){ if(normVal((parsedItems[it[0]]||{}).answer)==='yes') y++; }
    return { score:y, max:(tool.countMax||tool.items.length) };
  }
  return null;
}

function deriveOverall(tool, parsedItems){
  // jugement global pour les outils 'judgment'
  if (tool.overallKind === 'confidence') { // AMSTAR-2
    let critFlaws=0, weaknesses=0;
    for (const it of tool.items){ const k=it[0], opts=it[2]||{}; const a=normVal((parsedItems[k]||{}).answer); const bad=(a==='no'); const weak=(a==='partial_yes'); if(bad){ if(opts.critical) critFlaws++; else weaknesses++; } else if(weak){ weaknesses++; } }
    if (critFlaws>1) return 'critically_low';
    if (critFlaws===1) return 'low';
    if (weaknesses>1) return 'moderate';
    return 'high';
  }
  // RoB2 / ROBINS-I / ROBIS / QUADAS-2 : pire domaine
  const order = { low:0, unclear:1, some_concerns:1, moderate:1, no_information:1, high:3, serious:2, critical:3 };
  let worst='low', wv=-1;
  for (const it of tool.items){ if(tool.kind==='matrix' && it[0].indexOf('app_')===0) continue; const a=normVal((parsedItems[it[0]]||{}).answer); const v=(order[a]!=null?order[a]:1); if(v>wv){ wv=v; worst=a; } }
  return worst || 'low';
}

function normLevel(tool, overall, sc){
  if (tool.kind==='score' || tool.kind==='count'){ if(!sc||!sc.max) return 'unknown'; const p=sc.score/sc.max; return p>=0.66?'low':(p>=0.34?'medium':'high'); }
  const o=normVal(overall);
  if (tool.overallKind==='confidence'){ if(o==='high'||o==='moderate') return 'low'; if(o==='low') return 'medium'; if(o==='critically_low') return 'high'; return 'unknown'; }
  if (!o) return 'unknown';
  if (o.indexOf('no_info')>=0) return 'unknown';
  if (o.indexOf('low')>=0) return 'low';
  if (o.indexOf('some')>=0||o.indexOf('moderate')>=0||o.indexOf('unclear')>=0) return 'medium';
  if (o.indexOf('high')>=0||o.indexOf('serious')>=0||o.indexOf('critical')>=0) return 'high';
  return 'unknown';
}

function buildPrompt(a, tool, basis, text){
  const allowed = tool.answers.map(function(x){return '"'+x+'"';}).join(' | ');
  const lines = tool.items.map(function(it){ return '    "'+it[0]+'": { "answer": '+allowed+', "justification": "<short, grounded in the text>" },   // '+it[1]; }).join('\n');
  const wantsOverall = tool.overall ? (',\n  "overall": ' + (tool.overallKind==='confidence' ? '"high" | "moderate" | "low" | "critically_low"' : allowed)) : '';
  return [
    'You are a methodologist assessing methodological quality / risk of bias using the ' + tool.name + ' tool.',
    'TEXT BASIS: ' + (basis==='fulltext'?'full text (PDF)':'abstract only - be conservative; if the text does not allow a confident answer, use the most cautious allowed value'),
    '',
    '=== STUDY TEXT ===',
    'TITLE: ' + ((a.title||'').substring(0,200)),
    text.substring(0,22000),
    '',
    '=== TASK ===',
    'Answer EVERY item below using ONLY the allowed values, with a one-sentence justification grounded in the text.',
    'Return STRICT JSON ONLY (no markdown, nothing before/after), exactly this shape:',
    '{',
    '  "items": {',
    lines,
    '  }' + wantsOverall + ',',
    '  "comment": "<one short overall sentence>"',
    '}'
  ].join('\n');
}

function coerceAns(rawAns){
  var s0=(rawAns==null?'':String(rawAns)).toLowerCase().trim();
  if(s0==='1'||s0==='true'||s0==='y'||s0==='oui'||s0==='present') s0='yes';
  else if(s0==='0'||s0==='false'||s0==='n'||s0==='non'||s0==='absent') s0='no';
  if(s0.indexOf('partial')>=0) s0='partial_yes';
  return s0.replace(/\s+/g,'_').replace(/[^a-z_]/g,'');
}
function assess(tool, parsed){
  const out = {};
  const raw = (parsed && parsed.items) || {};
  const hasPY = tool.answers.indexOf('partial_yes')>=0;
  for (const it of tool.items){ const k=it[0]; var e=raw[k]; var rawAns, just='';
    if(e && typeof e==='object'){ rawAns=(e.answer!=null?e.answer:(e.value!=null?e.value:(e.judgement!=null?e.judgement:(e.judgment!=null?e.judgment:(e.rating!=null?e.rating:e.response))))); just=(e.justification!=null?e.justification:(e.reason!=null?e.reason:(e.justif!=null?e.justif:(e.rationale||'')))); }
    else { rawAns=e; }
    let ans=coerceAns(rawAns);
    if(ans==='partial_yes' && !hasPY) ans='partial';
    if(tool.answers.indexOf(ans)<0) ans='';
    out[k]={ answer:ans, justification:(just!=null?String(just).substring(0,300):'') }; }
  const sc = computeScore(tool, out);
  let overall='';
  if (tool.overall){ overall = normVal(parsed && parsed.overall) || deriveOverall(tool, out); }
  const level = normLevel(tool, overall, sc);
  return { items:out, score:sc, overall:overall, level:level, comment:(parsed && parsed.comment?String(parsed.comment).substring(0,300):'') };
}

// ----- config : override outil -----
let OVERRIDE = '';
try {
  const cfg = await this.helpers.httpRequest({ method:'GET', url:'http://host.docker.internal:8080/api/config', timeout:5000, json:true }) || {};
  const o = (cfg.rob_tool||'').toString().trim().toLowerCase();
  if (o && o!=='auto' && TOOLS[o]) OVERRIDE = o;
} catch(e) {}
// override possible aussi via articles[0]._rob_tool_override (injecte par UI)
if (!OVERRIDE && articles[0] && articles[0]._rob_tool_override && TOOLS[articles[0]._rob_tool_override]) OVERRIDE = articles[0]._rob_tool_override;

const results = [];
for (let i=0;i<articles.length;i++){
  const article = articles[i];
  const fam = detectFamily(article);
  let toolId = OVERRIDE || DEFAULT_BY_FAMILY[fam] || 'robinsi';
  const tool = TOOLS[toolId];
  // texte
  let text='', basis='abstract';
  const pdf = article.pdf_local || '';
  if (pdf){ try { const resp=await this.helpers.httpRequest({ method:'POST', url:PROXY+'/extract-pdf', body:JSON.stringify({pdf_path:pdf,max_chars:26000,skip_biblio:true}), headers:{'Content-Type':'application/json'}, json:true, timeout:60000 }); if(resp&&resp.success&&resp.text){ text=resp.text.substring(0,24000); basis='fulltext'; } } catch(e){} }
  if (!text){ text=(article.abstract||'').toString(); basis='abstract'; }
  if (!text || text.length<60){ results.push({ json:Object.assign({},article,{ _rob_status:'no_text', _rob_basis:basis, _rob_tool:tool.name, _rob_tool_id:toolId, _rob_design:fam, _rob_level:'unknown', _needs_human_review:true, _rob_comment:'Ni PDF ni abstract exploitable' }) }); continue; }
  const prompt = buildPrompt(article, tool, basis, text);
  let parsed=null, raw1='';
  try { const rp=await this.helpers.httpRequest({ method:'POST', url:PROXY+'/api/generate', body:JSON.stringify({ model:'qwen2.5:3b', prompt:prompt, stream:false, format:'json', options:{temperature:0,num_predict:2000,num_ctx:32768}, keep_alive:'30m', _ultralab_task:'chat' }), headers:{'Content-Type':'application/json'}, json:true, timeout:900000 }); raw1=(rp&&rp.response)||''; parsed=extractJson(raw1); } catch(e){ raw1='ERR:'+(e.message||e); }
  if (!parsed || !parsed.items){ results.push({ json:Object.assign({},article,{ _rob_status:'parse_failed', _rob_basis:basis, _rob_tool:tool.name, _rob_tool_id:toolId, _rob_design:fam, _rob_level:'unknown', _needs_human_review:true, _rob_comment:'JSON non exploitable', _rob_raw_preview:raw1.substring(0,200).replace(/\s+/g,' '), _rob_prompt:prompt }) }); continue; }
  const A = assess(tool, parsed);
  const needsHuman = (basis==='abstract') || (A.level==='unknown');
  results.push({ json:Object.assign({},article,{
    _rob_status:'ok', _rob_basis:basis, _rob_design:fam, _rob_tool:tool.name, _rob_tool_id:toolId,
    _rob_items:A.items, _rob_item_defs:tool.items, _rob_kind:tool.kind, _rob_score:(A.score?A.score.score:null), _rob_score_max:(A.score?A.score.max:null),
    _rob_overall:A.overall, _rob_level:A.level, _rob_comment:A.comment,
    _needs_human_review:(article._needs_human_review||needsHuman), _rob_prompt:prompt,
    _rob_raw_preview: raw1.substring(0,300).replace(/\s+/g,' ')
  }) });
}
console.log('[RoB v2] M1 termine');

// ===== DOUBLE RELECTURE (opt-in, modele different) : accord par item + kappa sur niveau global =====
try {
  let cfg={}; try { cfg=await this.helpers.httpRequest({ method:'GET', url:'http://host.docker.internal:8080/api/config', timeout:5000, json:true })||{}; } catch(e){}
  const on = cfg.screening_double_enabled===true; const m1=(cfg.ollama_model||'').trim(); const m2=(cfg.screening_model_2||'').trim();
  if (on && m2 && m2!==m1){
    const cats=['low','medium','high']; const c1={low:0,medium:0,high:0},c2={low:0,medium:0,high:0}; let nb=0,ag=0; let itemAgSum=0, itemAgN=0;
    for (let i=0;i<results.length;i++){
      const r=results[i].json; if(!r._rob_prompt||!r._rob_tool_id) continue; const tool=TOOLS[r._rob_tool_id]; if(!tool) continue;
      let raw2='',p2=null;
      try { const rp=await this.helpers.httpRequest({ method:'POST', url:PROXY+'/api/generate', body:JSON.stringify({ model:m2, prompt:r._rob_prompt, stream:false, format:'json', options:{temperature:0,num_predict:2000,num_ctx:32768}, keep_alive:'30m', _ultralab_task:'screening_pass2' }), headers:{'Content-Type':'application/json'}, json:true, timeout:900000 }); raw2=(rp&&rp.response)||''; p2=extractJson(raw2); } catch(e){}
      if (p2){
        const B=assess(tool,p2); r._rob_items_2=B.items; r._rob_overall_2=B.overall; r._rob_score_2=(B.score?B.score.score:null); r._rob_level_2=B.level; r.rob_model2=m2;
        // accord par item
        let same=0,tot=0; for(const it of tool.items){ const k=it[0]; tot++; if((r._rob_items[k]||{}).answer===(B.items[k]||{}).answer) same++; }
        const itemAg = tot?Math.round(same/tot*1000)/10:null; r._rob_item_agreement=itemAg; if(itemAg!=null){ itemAgSum+=itemAg; itemAgN++; }
        const l1=r._rob_level, l2=B.level; const ok=(l1===l2); r._rob_agreement=ok?'agree':'disagree'; if(!ok) r._needs_human_review=true;
        if(cats.indexOf(l1)>=0&&cats.indexOf(l2)>=0){ nb++; if(ok)ag++; c1[l1]++; c2[l2]++; }
      }
    }
    let k=null; if(nb>0){ const po=ag/nb; let pe=0; for(let x=0;x<cats.length;x++){const c=cats[x]; pe+=(c1[c]/nb)*(c2[c]/nb);} k=(pe<1)?((po-pe)/(1-pe)):1; }
    const kr=(k===null)?null:Math.round(k*1000)/1000;
    function kl(v){ if(v===null)return 'n/a'; if(v<0)return 'poor'; if(v<=0.2)return 'slight'; if(v<=0.4)return 'fair'; if(v<=0.6)return 'moderate'; if(v<=0.8)return 'substantial'; return 'almost perfect'; }
    const sum={ enabled:true, phase:'risk-of-bias', model_1:m1, model_2:m2, n_double:nb, n_agree:ag, n_disagree:(nb-ag), percent_agreement:(nb?Math.round(ag/nb*1000)/10:null), mean_item_agreement:(itemAgN?Math.round(itemAgSum/itemAgN*10)/10:null), cohen_kappa:kr, kappa_interpretation:kl(kr) };
    console.log('[RoB double] kappa='+kr+' ('+sum.kappa_interpretation+') item_agree='+sum.mean_item_agreement+'% sur '+nb);
    for (let j=0;j<results.length;j++){ results[j].json._rob_double=sum; }
  }
} catch(e){ console.log('[RoB double] err '+e.message); }

for (let c=0;c<results.length;c++){ if(results[c].json._rob_prompt) delete results[c].json._rob_prompt; }
return results;
